import subprocess
import sys

def parse_nvidia_smi():
    try:
        result = subprocess.run(
            ['nvidia-smi', '--query-gpu=index,name,temperature.gpu,utilization.gpu,memory.total,memory.used,memory.free,power.draw', '--format=csv,noheader,nounits'],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            check=True
        )
        lines = [line.strip().split(', ') for line in result.stdout.strip().split('\n') if line.strip()]
        return lines
    except Exception as e:
        print(f"Error running nvidia-smi: {e}", file=sys.stderr)
        return []

def validate_gpu_metrics(gpu_data):
    anomalies = []
    for i, gpu in enumerate(gpu_data):
        index = gpu[0]
        temp = int(gpu[2])
        util_gpu = int(gpu[3])
        mem_total = int(gpu[4])
        mem_used = int(gpu[5])
        mem_free = int(gpu[6])
        power_draw = float(gpu[7])

        if temp >= 85:
            anomalies.append(f"GPU {index}: Temperature too high ({temp}°C)")

        if mem_used >= mem_total:
            anomalies.append(f"GPU {index}: Memory usage at or above 100% ({mem_used}/{mem_total})")

        if util_gpu >= 95:
            anomalies.append(f"GPU {index}: High GPU utilization ({util_gpu}%)")

        if power_draw > 300:
            anomalies.append(f"GPU {index}: High power draw ({power_draw}W)")

    return anomalies

def main():
    gpu_data = parse_nvidia_smi()
    if not gpu_data:
        print("No GPU data retrieved.")
        return

    anomalies = validate_gpu_metrics(gpu_data)
    if anomalies:
        for anomaly in anomalies:
            print(f"WARNING: {anomaly}")
    else:
        print("All GPU metrics within acceptable thresholds.")

if __name__ == "__main__":
    main()
